+fn runtime_risk_base_score(capability: &str, method: &str, policy_reason: &str) -> f64 {
+    let capability_score = match capability {
+        "exec" => 0.95,
+        "env" => 0.85,
+        "http" => 0.70,
+        "write" => 0.45,
+        "tool" => 0.50,
+        "session" => 0.35,
+        "events" => 0.30,
+        "ui" => 0.20,
+        "read" => 0.15,
+        _ => 0.25,
+    };
+
+    let method_bonus = match method {
+        "exec" => 0.20,
+        "http" => 0.12,
+        "tool" => 0.08,
+        _ => 0.0,
+    };
